import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { authAPI } from "../services/api";
import { useAuth } from "../context/AuthContext";

const BACKEND = process.env.REACT_APP_API_URL?.replace("/api","") || "http://localhost:5000";

export default function Signup() {
  const nav = useNavigate();
  const { login } = useAuth();
  const [form, setForm] = useState({ name:"", email:"", password:"" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (form.password.length < 6) { setError("Password must be at least 6 characters"); return; }
    setLoading(true); setError("");
    try {
      const r = await authAPI.signup(form);
      login(r.data.user, r.data.token);
      nav("/dashboard");
    } catch (err) {
      setError(err.response?.data?.message || err.response?.data?.errors?.[0]?.message || "Signup failed");
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight:"100vh", background:"var(--bg)", display:"flex", alignItems:"center", justifyContent:"center", padding:"2rem", fontFamily:"'Space Grotesk',sans-serif" }}>
      <div style={{ width:"100%", maxWidth:420, background:"var(--card-bg)", border:"1px solid var(--border)", borderRadius:20, padding:"2.5rem" }}>
        <div style={{ textAlign:"center", marginBottom:"2rem" }}>
          <Link to="/" style={{ textDecoration:"none" }}>
            <div style={{ fontFamily:"'Syne',sans-serif", fontWeight:800, fontSize:"1.4rem", marginBottom:".4rem" }}>
              <span style={{ color:"var(--blue)" }}>SkillGraph</span><span style={{ color:"var(--purple)" }}>AI</span>
            </div>
          </Link>
          <p style={{ color:"var(--muted)", fontSize:".88rem" }}>Create your free account</p>
        </div>

        <div style={{ display:"flex", flexDirection:"column", gap:".6rem", marginBottom:"1.5rem" }}>
          <a href={`${BACKEND}/api/auth/google`} style={{ textDecoration:"none" }}>
            <button type="button" style={{ width:"100%", padding:".75rem", background:"#fff", border:"1px solid #ddd", borderRadius:10, display:"flex", alignItems:"center", justifyContent:"center", gap:".6rem", cursor:"pointer", color:"#333", fontWeight:600, fontSize:".88rem", fontFamily:"inherit" }}>
              <svg width="18" height="18" viewBox="0 0 48 48"><path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/><path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/><path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/><path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.35-8.16 2.35-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/></svg>
              Sign up with Google
            </button>
          </a>
          <a href={`${BACKEND}/api/auth/linkedin`} style={{ textDecoration:"none" }}>
            <button type="button" style={{ width:"100%", padding:".75rem", background:"#0077B5", border:"none", borderRadius:10, display:"flex", alignItems:"center", justifyContent:"center", gap:".6rem", cursor:"pointer", color:"#fff", fontWeight:600, fontSize:".88rem", fontFamily:"inherit" }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="white"><path d="M20.447 20.452h-3.554v-5.569c0-1.328-.027-3.037-1.852-3.037-1.853 0-2.136 1.445-2.136 2.939v5.667H9.351V9h3.414v1.561h.046c.477-.9 1.637-1.85 3.37-1.85 3.601 0 4.267 2.37 4.267 5.455v6.286zM5.337 7.433c-1.144 0-2.063-.926-2.063-2.065 0-1.138.92-2.063 2.063-2.063 1.14 0 2.064.925 2.064 2.063 0 1.139-.925 2.065-2.064 2.065zm1.782 13.019H3.555V9h3.564v11.452zM22.225 0H1.771C.792 0 0 .774 0 1.729v20.542C0 23.227.792 24 1.771 24h20.451C23.2 24 24 23.227 24 22.271V1.729C24 .774 23.2 0 22.222 0h.003z"/></svg>
              Sign up with LinkedIn
            </button>
          </a>
        </div>

        <div style={{ display:"flex", alignItems:"center", gap:"1rem", marginBottom:"1.5rem" }}>
          <div style={{ flex:1, height:1, background:"var(--border)" }}/>
          <span style={{ color:"var(--muted)", fontSize:".78rem" }}>or email</span>
          <div style={{ flex:1, height:1, background:"var(--border)" }}/>
        </div>

        {error && <div style={{ background:"rgba(252,129,129,.08)", border:"1px solid rgba(252,129,129,.3)", borderRadius:8, padding:".7rem 1rem", color:"var(--red)", fontSize:".85rem", marginBottom:"1rem" }}>⚠️ {error}</div>}

        <form onSubmit={handleSubmit}>
          {[
            { name:"name",     type:"text",     label:"Full Name",    ph:"John Doe" },
            { name:"email",    type:"email",    label:"Email",        ph:"you@example.com" },
            { name:"password", type:"password", label:"Password (min 6)", ph:"••••••••" },
          ].map(f => (
            <div key={f.name} style={{ marginBottom:"1rem" }}>
              <label className="sg-label">{f.label}</label>
              <input type={f.type} required value={form[f.name]} onChange={e => setForm({...form,[f.name]:e.target.value})} placeholder={f.ph} className="sg-input"/>
            </div>
          ))}
          <div style={{ background:"var(--bg3)", border:"1px solid var(--border)", borderRadius:8, padding:".6rem 1rem", fontSize:".78rem", color:"var(--muted)", marginBottom:"1rem" }}>
            ✓ Free forever &nbsp;·&nbsp; ✓ No credit card &nbsp;·&nbsp; ✓ All 12 features included
          </div>
          <button type="submit" disabled={loading} className="sg-btn sg-btn-primary" style={{ width:"100%", justifyContent:"center" }}>
            {loading ? "Creating Account..." : "Create Account →"}
          </button>
        </form>

        <p style={{ textAlign:"center", marginTop:"1.25rem", color:"var(--muted)", fontSize:".85rem" }}>
          Already have an account? <Link to="/login" style={{ color:"var(--blue)", textDecoration:"none", fontWeight:600 }}>Sign in</Link>
        </p>
      </div>
    </div>
  );
}
